/// <summary>
/// Business event class for ETG DMS Revere Integration.
/// Sends the event using the provided contract data.
/// </summary>
[BusinessEvents(classStr(ETGDMSReverePurchAgreementIntegrationContract),
"ETG DMSPurchAgreemnet Reverse Integration ",
    "This  business event will trigger when agreement confirmation /returnorder/Invoce",
    ModuleAxapta::General)]
internal final class ETGDMSReverePurchAgreementIntegrationEventClass extends BusinessEventsBase
{
    private ETGDMSReverePurchAgreementIntegrationContract contract;


}

Method.Source:
public static ETGDMSReverePurchAgreementIntegrationEventClass newFromContract(ETGDMSReverePurchAgreementIntegrationContract _contract)
{
    ETGDMSReverePurchAgreementIntegrationEventClass event = new ETGDMSReverePurchAgreementIntegrationEventClass();
    event.parmDataContract(_contract);
    return event;
}

public ETGDMSReverePurchAgreementIntegrationContract parmDataContract( ETGDMSReverePurchAgreementIntegrationContract _contract = contract)
{
    contract = _contract;
    return contract;
}
